CREATE TABLE IF NOT EXISTS agents (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id), name VARCHAR(100) NOT NULL DEFAULT 'Пино', personality TEXT DEFAULT '', model_id VARCHAR(100) DEFAULT 'deepseek-chat', custom_endpoint TEXT DEFAULT '', custom_model_name VARCHAR(100) DEFAULT '', api_key_encrypted TEXT DEFAULT '', is_pino BOOLEAN DEFAULT false, memory_stats JSONB DEFAULT '{"events":0,"generalizations":0,"principles":0}', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS agent_memory (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), agent_id UUID NOT NULL REFERENCES agents(id), level VARCHAR(20) NOT NULL DEFAULT 'event', category VARCHAR(50) NOT NULL DEFAULT 'general', content TEXT NOT NULL, confidence FLOAT DEFAULT 0.5, embedding_data TEXT, source_count INTEGER DEFAULT 1, tags TEXT[] DEFAULT '{}', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS agent_room_members (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), chat_id UUID NOT NULL REFERENCES chats(id), agent_id UUID NOT NULL REFERENCES agents(id), tone VARCHAR(50) DEFAULT 'friendly', goal TEXT DEFAULT '', forbidden_topics TEXT[] DEFAULT '{}', custom_notes TEXT DEFAULT '', joined_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(chat_id, agent_id));